rss.channel:
{{ if eq .Title .Site.Title }}{{ .Site.Title }}{{ else }}{{ with .Title }}{{ . }} on {{ end }}{{ .Site.Title }}{{ end }}
{{ .Permalink }}
{{ printf "Recent content on %s" .Site.Title | plainify | transform.XMLEscape }}
Hugo -- gohugo.io
{{ .Site.Language.Locale | default "en" }}
{{ with .OutputFormats.Get "RSS" }}
  {{ printf "" .Permalink .MediaType.Type | safeHTML }}
{{ end }}
{{- $pages := .Site.RegularPages -}}
{{- range first 15 $pages -}}


  {{ .Title | plainify | transform.XMLEscape }}
  {{ .Permalink }}
  {{ .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" }}
  {{ .Permalink }}
  {{ .Summary | default .Plain | plainify | transform.XMLEscape }}
  {{ .Content | plainify | transform.XMLEscape }}

{{- end -}}
